module RefModule(clock,signal_uc, prog_or_kernel,reset);input signal_uc;
	input clock;
	input reset;
	output prog_or_kernel;
	reg pipeline_reg;


	always @(posedge clock) begin
		if(reset)begin
			pipeline_reg <= 0;
		end
		if((signal_uc == 1) && (pipeline_reg == 0))begin
			pipeline_reg <= 1;
		end 
		else if((signal_uc == 1) && (pipeline_reg == 1)) begin
			pipeline_reg <= 0;
		end

	end
	assign prog_or_kernel = pipeline_reg;


endmodule
